      role: "assistant",
      body: item.text,
      createdAt: updatedAtLabel,
    };
  }

  return null;
}

function threadItemToTimelineItem(item: CodexThreadItem): OffdexTimelineItem {
  if (isUserMessageItem(item)) {
    return {
      type: "userMessage",
      id: item.id,
      content: item.content.map((entry) => {
        switch (entry.type) {
          case "text":
            return { type: "text", text: entry.text };
          case "image":
            return { type: "image", url: entry.url };
          case "localImage":
            return { type: "localImage", path: entry.path };
          case "skill":
            return { type: "skill", name: entry.name, path: entry.path };
          case "mention":
            return { type: "mention", name: entry.name, path: entry.path };
        }
      }),
    };
  }

  if (isAgentMessageItem(item)) {
    return {
      type: "agentMessage",
      id: item.id,
      text: item.text,
      phase: item.phase ?? null,
    };
  }

  if (isReasoningItem(item)) {
    return {
      type: "reasoning",
      id: item.id,
      summary: [...item.summary],
      content: [...item.content],
    };
  }

  if (isPlanItem(item)) {
    return {
      type: "plan",
      id: item.id,
      text: item.text,
    };
  }

  if (isCommandExecutionItem(item)) {
    return {
      type: "commandExecution",
      id: item.id,
      command: item.command,
      cwd: item.cwd ?? null,
      status:
        item.status === "completed" ||
        item.status === "failed" ||
        item.status === "interrupted" ||
        item.status === "pending"
          ? item.status
          : "in_progress",
      aggregatedOutput: item.aggregatedOutput ?? "",
