          </p>
        ) : null}
        {isPlan ? (
          <p className="mt-3 text-[11px] opacity-60">Plan updates stream in-line for the active turn.</p>
        ) : null}
        {isUnknown ? <p className="mt-3 text-[11px] opacity-60">Runtime event</p> : null}
      </div>
    </article>
  );
}

