function upsertTimelineItem(turn: OffdexTurn, item: OffdexTimelineItem) {
  const existingIndex = turn.items.findIndex((entry) => entry.id === item.id);
  if (existingIndex >= 0) {
    turn.items[existingIndex] = item;
