  announcement: string | null;
  enabled: boolean;
  defaultEnabled: boolean;
}

export interface OffdexRemoteFileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  isFile: boolean;
}

export interface OffdexRemoteFileMatch {
  name: string;
  path: string;
  root: string;
  kind: "file" | "directory";
  score: number;

  return `resets in ${deltaHours}h`;
